// // This module is designed to capture and store the value of the input signal 'pm' on the falling edge of the clock signal 'clk'. The stored value can then be accessed at the output 'rndout'.
module top_module(pm,clk,rndout);input [63:0] pm; 
input clk; 
output [63:0] rndout; 
reg [63:0] t;



always @(posedge clk) 
begin
 t <= pm; 
end 
assign rndout=t;

endmodule
